var myok = false;

function hidePopupModel() {
    myDialog.modal('hide');
}






function doPopupModal(btn) {

    this.disabled = true;
    this.value = "Processing...";

    if (myok) {
        myok = false;
        return true;
    }


    var flatpkr = new flatpickr('#time', {
        enableTime: true,
        noCalendar: true,
        dateFormat: "H:i",
        defaultDate: new Date(),
        time_24hr: true
    });


    var myDialog = $("#divCallbackTiming");

    var now = new Date();
     now.setMinutes(now.getMinutes() - now.getTimezoneOffset());
    //$('#divCallbackTiming').find('#time').val(now.toISOString().slice(0, 16));

    myDialog.modal('show');


    $('#divCallbackTiming').find("input[name='BtnCallBackSave']").click(function (e) {
        e.preventDefault();


        let currentdt = $('#callbackdt')[0].innerText;
        let currentdttime = $('#divCallbackTiming').find('input[id=time]').val();

        console.log(currentdttime);
        if (currentdttime == null || currentdttime == '') {
            alert("Please fill in callback timing.");
            return false;
        }


        let dt = currentdt + ' ' + $('#divCallbackTiming').find('input[id=time]').val();
        let dtobj = new Date(dt);

        if (dtobj <= Date.now()) {
            alert("Call back timing must be later than current date time.");
            return false;
        }

        var callbacktiming = dtobj.toISOString();


        $("#<%=hidinpouttoatiming.ClientID %>").val(callbacktiming);
        myok = true;

        btn.click();

        myDialog.modal('hide');


        return true;
    })


    return false;
}
